function solve(nums, target) {
    const N = nums.length;
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    const NA = Math.floor(N / 2);
    const A = nums.slice(0, NA);
    const B = nums.slice(NA);

    /**
     * Generates a map where key is the XOR sum achievable by a subset,
     * and value is the maximum size of the subset achieving that sum.
     * @param {number[]} arr 
     * @returns {Map<number, number>}
     */
    function generate_subsets(arr) {
        const L = arr.length;
        // Map: XOR Sum -> Max Size
        const results = new Map();

        // Initialize with the empty set: XOR sum 0, size 0
        results.set(0, 0);

        // Iterate through all 2^L subsets using bitmasks
        for (let mask = 1; mask < (1 << L); mask++) {
            let xor_sum = 0;
            let size = 0;

            for (let i = 0; i < L; i++) {
                if ((mask >> i) & 1) {
                    xor_sum ^= arr[i];
                    size++;
                }
            }

            // Update the map, keeping the maximum size for any given XOR sum
            if (!results.has(xor_sum) || size > results.get(xor_sum)) {
                results.set(xor_sum, size);
            }
        }
        return results;
    }

    const mapA = generate_subsets(A);
    const mapB = generate_subsets(B);

    let maxTotalSize = -1;

    // Combine results
    for (const [xorA, sizeA] of mapA.entries()) {
        // We need xorA ^ xorB = target, so xorB = target ^ xorA
        const xorBReq = target ^ xorA;

        if (mapB.has(xorBReq)) {
            const sizeB = mapB.get(xorBReq);
            const currentSize = sizeA + sizeB;
            if (currentSize > maxTotalSize) {
                maxTotalSize = currentSize;
            }
        }
    }

    if (maxTotalSize === -1) {
        return -1;
    } else {
        // Minimum removals = Total size - Maximum retained size
        return N - maxTotalSize;
    }
}

