use std::collections::HashMap;

fn generate_subsets(arr: &[i64]) -> HashMap<i64, i64> {
    let mut results: HashMap<i64, i64> = HashMap::new();
    // Initialize with the empty set: XOR sum 0, size 0
    results.insert(0, 0);

    let l = arr.len();
    if l == 0 {
        return results;
    }

    // Iterate over all masks from 1 to 2^L - 1
    for mask in 1..(1 << l) {
        let mut xor_sum = 0i64;
        let mut size = 0i64;

        for i in 0..l {
            if (mask >> i) & 1 == 1 {
                xor_sum ^= arr[i];
                size += 1;
            }
        }

        // Update the map, keeping the maximum size for any given XOR sum
        results.entry(xor_sum)
               .and_modify(|e| *e = (*e).max(size))
               .or_insert(size);
    }
    results
}

fn solve(nums: Vec<i64>, target: i64) -> i64 {
    let n = nums.len() as i64;
    if n == 0 {
        return if target == 0 { 0 } else { -1 };
    }

    // Meet-in-the-Middle split
    let na = (n / 2) as usize;

    // Split nums into A and B
    let a = &nums[0..na];
    let b = &nums[na..];

    // Generate subset XOR maps: XOR_Sum -> Max_Size
    let map_a = generate_subsets(a);
    let map_b = generate_subsets(b);

    let mut max_total_size: i64 = -1;

    // Combine results
    for (&xor_a, &size_a) in map_a.iter() {
        // We need xor_a ^ xor_b = target, so xor_b = target ^ xor_a
        let xor_b_req = target ^ xor_a;

        if let Some(&size_b) = map_b.get(&xor_b_req) {
            let current_size = size_a + size_b;
            if current_size > max_total_size {
                max_total_size = current_size;
            }
        }
    }

    if max_total_size == -1 {
        // Impossible to achieve target
        -1
    } else {
        // Minimum removals = Total size - Maximum retained size
        n - max_total_size
    }
}

